17	// RBTDRK — gauntlet canonical-establish fixture (§2 of release qualification)
18	//
19	// Establishes long-lived canonical state the gauntlet's downstream fixtures
20	// inherit:
21	//   1. depot_levy        — install canonical RBRR prefixes; levy a fresh canest depot
22	//   2. governor_mantle   — mantle governor against the canonical depot
23	//   3. retriever_invest  — invest a canonical retriever SA + access-probe
24	//   4. director_invest   — invest a canonical director SA + access-probe
25	//
26	// Disposition: StateProgressing. Each case carries a precondition probe via
27	// rbtdrb_Probe so a-la-carte single-case rerun fails cleanly when an earlier
28	// case's state is absent. Tabtarget invocations are responsible for waiting
29	// out their own propagation (no separate iam-propagation-wait case).
30	
31	use std::path::{Path, PathBuf};
32	use std::process::Command;
33	
34	use crate::case;
35	use crate::rbtdrb_probe::{rbtdrb_assert, rbtdrb_Probe};
36	use crate::rbtdrc_crucible::rbtdrc_with_ctx;
37	use crate::rbtdre_engine::{rbtdre_Section, rbtdre_Verdict};
38	use crate::rbtdri_invocation::{
39	    rbtdri_invoke_global, rbtdri_invoke_imprint, rbtdri_read_burv_fact, rbtdri_Context,
40	    rbtdri_InvokeResult, RBTDRI_BURV_OUTPUT_SUBDIR,
41	};
42	use crate::rbtdrm_manifest::{
43	    RBTDRM_COLOPHON_ACCESS_PROBE, RBTDRM_COLOPHON_DEPOT_LEVY, RBTDRM_COLOPHON_DEPOT_LIST,
44	    RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR, RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
45	    RBTDRM_COLOPHON_GOV_MANTLE,
46	};
47	
48	// ── Canonical-fixture identities ─────────────────────────────
49	
50	/// Canonical RBRR prefix markers installed by case 1. Distinct from
51	/// pristine's throwaway prefixes (prlc-/prlr-) — case 2's probe detects
52	/// canonical state by reading the moniker's family stem from rbrr.env.
53	pub(crate) const RBTDRK_CANONICAL_CLOUD_PREFIX: &str = "canc-";
54	pub(crate) const RBTDRK_CANONICAL_RUNTIME_PREFIX: &str = "canr-";
55	
56	/// Family stem for canonical depots; six-digit auto-increment suffix per run.
57	/// Depots persist post-success for operator inspection; reruns pick the next
58	/// free suffix by walking depot_list output. Era-bumped past the prior
59	/// `canest` family to side-step pending-delete projectId reservations from
60	/// burned-bridges teardown.
61	pub(crate) const RBTDRK_FAMILY_STEM: &str = "canest2";
62	
63	/// Static identities for the canonical SA cycle. Stable across runs because
64	/// each run uses a fresh canest depot project.
65	const RBTDRK_IDENTITY_RETRIEVER: &str = "canest-ret";
66	const RBTDRK_IDENTITY_DIRECTOR: &str = "canest-dir";
67	
68	const RBTDRK_FAMILY_NUMERIC_FLOOR: u32 = 100000;
69	const RBTDRK_FAMILY_NUMERIC_WIDTH: usize = 6;
70	
71	const RBTDRK_FACT_EXT_DEPOT: &str = "depot";
72	const RBTDRK_FACT_EXT_DEPOT_PROJECT: &str = "depot-project";
73	const RBTDRK_FACT_GOVERNOR_SA_EMAIL: &str = "rbgp_fact_governor_sa_email";
74	
75	const RBTDRK_FIELD_RBRR_CLOUD_PREFIX: &str = "RBRR_CLOUD_PREFIX";
76	const RBTDRK_FIELD_RBRR_RUNTIME_PREFIX: &str = "RBRR_RUNTIME_PREFIX";
77	const RBTDRK_FIELD_RBRR_DEPOT_MONIKER: &str = "RBRR_DEPOT_MONIKER";
78	const RBTDRK_FIELD_RBRR_SECRETS_DIR: &str = "RBRR_SECRETS_DIR";
79	
80	const RBTDRK_RBRR_FILE: &str = ".rbk/rbrr.env";
81	const RBTDRK_RBRA_FILE: &str = "rbra.env";
82	
83	// ── Helpers ──────────────────────────────────────────────────
84	
85	/// Read an env-file value or None if absent. Mirrors pristine's helper —
86	/// kept local to avoid coupling canonical-establish to pristine-lifecycle.
87	fn rbtdrk_read_env_value(path: &Path, key: &str) -> Option<String> {
88	    let content = std::fs::read_to_string(path).ok()?;
89	    let prefix = format!("{}=", key);
90	    for line in content.lines() {
91	        let trimmed = line.trim_start();
92	        if trimmed.starts_with('#') {
93	            continue;
94	        }
95	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
96	            return Some(rest.to_string());
97	        }
98	    }
99	    None
100	}
101	
102	fn rbtdrk_resolve(root: &Path, raw: &str) -> PathBuf {
103	    if Path::new(raw).is_absolute() {
104	        PathBuf::from(raw)
105	    } else {
106	        root.join(raw)
107	    }
108	}
109	
110	fn rbtdrk_replace_env_fields(content: &str, pairs: &[(&str, &str)]) -> String {
111	    let mut result: String = content
112	        .lines()
113	        .map(|line| {
114	            for (key, value) in pairs {
115	                let assign = format!("{}=", key);
116	                if line.starts_with(&assign) {
117	                    return format!("{}{}", assign, value);
118	                }
119	            }
120	            line.to_string()
121	        })
122	        .collect::<Vec<_>>()
123	        .join("\n");
124	    if content.ends_with('\n') {
125	        result.push('\n');
126	    }
127	    result
128	}
129	
130	fn rbtdrk_git_add_and_commit(root: &Path, file: &str, message: &str) -> Result<(), String> {
131	    let add = Command::new("git")
132	        .args(["add", file])
133	        .current_dir(root)
134	        .output()
135	        .map_err(|e| format!("rbtdrk: git add invocation failed: {}", e))?;
136	    if !add.status.success() {
137	        return Err(format!(
138	            "rbtdrk: git add failed (exit {}): {}",
139	            add.status.code().unwrap_or(-1),
140	            String::from_utf8_lossy(&add.stderr).trim()
141	        ));
142	    }
143	    let commit = Command::new("git")
144	        .args(["commit", "-m", message])
145	        .current_dir(root)
146	        .output()
147	        .map_err(|e| format!("rbtdrk: git commit invocation failed: {}", e))?;
148	    if !commit.status.success() {
149	        return Err(format!(
150	            "rbtdrk: git commit failed (exit {}): {}",
151	            commit.status.code().unwrap_or(-1),
152	            String::from_utf8_lossy(&commit.stderr).trim()
153	        ));
154	    }
155	    Ok(())
156	}
157	
158	/// Resolve canonical RBRA path for a role: <RBRR_SECRETS_DIR>/<role>/rbra.env.
159	fn rbtdrk_canonical_rbra(root: &Path, role: &str) -> Result<PathBuf, String> {
160	    let rbrr = root.join(RBTDRK_RBRR_FILE);
161	    let secrets_dir = rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_SECRETS_DIR)
162	        .ok_or_else(|| format!("RBRR_SECRETS_DIR missing from {}", rbrr.display()))?;
163	    if secrets_dir.is_empty() {
164	        return Err(format!("RBRR_SECRETS_DIR is blank in {}", rbrr.display()));
165	    }
166	    Ok(rbtdrk_resolve(root, &secrets_dir)
167	        .join(role)
168	        .join(RBTDRK_RBRA_FILE))
169	}
170	
171	// ── Canonical-prefix install (case 1) ───────────────────────
172	
173	/// Idempotently install canc-/canr- prefixes into rbrr.env. Returns Ok
174	/// without committing when prefixes already match the canonical markers;
175	/// otherwise rewrites both lines and commits.
176	pub(crate) fn rbtdrk_install_canonical_prefixes(root: &Path) -> Result<(), String> {
177	    let rbrr = root.join(RBTDRK_RBRR_FILE);
178	    let cloud = rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_CLOUD_PREFIX).unwrap_or_default();
179	    let runtime =
180	        rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_RUNTIME_PREFIX).unwrap_or_default();
181	    if cloud == RBTDRK_CANONICAL_CLOUD_PREFIX && runtime == RBTDRK_CANONICAL_RUNTIME_PREFIX {
182	        return Ok(());
183	    }
184	    let content = std::fs::read_to_string(&rbrr)
185	        .map_err(|e| format!("rbtdrk: read {}: {}", rbrr.display(), e))?;
186	    let new_content = rbtdrk_replace_env_fields(
187	        &content,
188	        &[
189	            (
190	                RBTDRK_FIELD_RBRR_CLOUD_PREFIX,
191	                RBTDRK_CANONICAL_CLOUD_PREFIX,
192	            ),
193	            (
194	                RBTDRK_FIELD_RBRR_RUNTIME_PREFIX,
195	                RBTDRK_CANONICAL_RUNTIME_PREFIX,
196	            ),
197	        ],
198	    );
199	    std::fs::write(&rbrr, &new_content)
200	        .map_err(|e| format!("rbtdrk: write {}: {}", rbrr.display(), e))?;
201	    let commit_msg = format!(
202	        "canonical-establish fixture: install canonical RBRR prefixes ({}/{})",
203	        RBTDRK_CANONICAL_CLOUD_PREFIX, RBTDRK_CANONICAL_RUNTIME_PREFIX
204	    );
205	    rbtdrk_git_add_and_commit(root, RBTDRK_RBRR_FILE, &commit_msg)
206	}
207	
208	fn rbtdrk_install_depot_moniker(root: &Path, moniker: &str) -> Result<(), String> {
209	    let rbrr = root.join(RBTDRK_RBRR_FILE);
210	    let content = std::fs::read_to_string(&rbrr)
211	        .map_err(|e| format!("rbtdrk: read {}: {}", rbrr.display(), e))?;
212	    let new_content =
213	        rbtdrk_replace_env_fields(&content, &[(RBTDRK_FIELD_RBRR_DEPOT_MONIKER, moniker)]);
214	    std::fs::write(&rbrr, &new_content)
215	        .map_err(|e| format!("rbtdrk: write {}: {}", rbrr.display(), e))?;
216	    let commit_msg = format!(
217	        "canonical-establish fixture: set {}={}",
218	        RBTDRK_FIELD_RBRR_DEPOT_MONIKER, moniker
219	    );
220	    rbtdrk_git_add_and_commit(root, RBTDRK_RBRR_FILE, &commit_msg)
221	}
222	
223	/// Compose depot project_id from kindled regime values: <CLOUD>d-<moniker>.
224	fn rbtdrk_compose_project_id(root: &Path, moniker: &str) -> Result<String, String> {
225	    let rbrr = root.join(RBTDRK_RBRR_FILE);
226	    let cloud_prefix = rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_CLOUD_PREFIX)
227	        .ok_or_else(|| format!("RBRR_CLOUD_PREFIX missing from {}", rbrr.display()))?;
228	    Ok(format!("{}d-{}", cloud_prefix, moniker))
229	}
230	
231	/// Pick the next free moniker for `family_stem` by walking the depot_list
232	/// invocation's BURV output dir for `<family>NNNNNN.depot` files. Returns
233	/// `<family>RBTDRK_FAMILY_NUMERIC_FLOOR` when no matching files exist.
234	///
235	/// Caller contract: `list_result` MUST be from a freshly-invoked depot_list
236	/// that ran in the current process. The fact-file scan IS the collision
237	/// check — stale state means picking a colliding moniker. Do not reuse a
238	/// `list_result` across cases or pass an operator-cached value.
239	fn rbtdrk_pick_next_moniker(
240	    list_result: &rbtdri_InvokeResult,
241	    family_stem: &str,
242	) -> Result<String, String> {
243	    let dir = list_result.burv_output.join(RBTDRI_BURV_OUTPUT_SUBDIR);
244	    let entries = match std::fs::read_dir(&dir) {
245	        Ok(e) => e,
246	        Err(_) => {
247	            return Ok(format!("{}{}", family_stem, RBTDRK_FAMILY_NUMERIC_FLOOR));
248	        }
249	    };
250	    let suffix_ext = format!(".{}", RBTDRK_FACT_EXT_DEPOT);
251	    let mut max_suffix: Option<u32> = None;
252	    for entry in entries.flatten() {
253	        let name = match entry.file_name().into_string() {
254	            Ok(n) => n,
255	            Err(_) => continue,
256	        };
257	        let stem = match name.strip_suffix(&suffix_ext) {
258	            Some(s) => s,
259	            None => continue,
260	        };
261	        let numeric = match stem.strip_prefix(family_stem) {
262	            Some(s) => s,
263	            None => continue,
264	        };
265	        if numeric.len() != RBTDRK_FAMILY_NUMERIC_WIDTH {
266	            continue;
267	        }
268	        let parsed: u32 = match numeric.parse() {
269	            Ok(n) => n,
270	            Err(_) => continue,
271	        };
272	        max_suffix = Some(max_suffix.map_or(parsed, |m| m.max(parsed)));
273	    }
274	    let next = match max_suffix {
275	        Some(m) => m + 1,
276	        None => RBTDRK_FAMILY_NUMERIC_FLOOR,
277	    };
278	    Ok(format!("{}{}", family_stem, next))
279	}
280	
281	fn rbtdrk_invoke_logged(
282	    ctx: &mut rbtdri_Context,
283	    colophon: &str,
284	    args: &[&str],
285	    extra_env: &[(&str, &str)],
286	    dir: &Path,
287	    label: &str,
288	) -> Result<rbtdri_InvokeResult, String> {
289	    let result = rbtdri_invoke_global(ctx, colophon, args, extra_env)?;
290	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &result.stdout);
291	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &result.stderr);
292	    Ok(result)
293	}
294	
295	// ── Probes ───────────────────────────────────────────────────
296	
297	/// Probes are pure `fn() -> Result<(), String>` per the rbtdrb_Probe shape and
298	/// have no context, so they read the project root from current_dir() — theurge
299	/// always launches from the project root.
300	fn rbtdrk_probe_root() -> Result<PathBuf, String> {
301	    std::env::current_dir().map_err(|e| format!("cannot resolve project root: {}", e))
302	}
303	
304	/// Case 1 probe: rbrr.env exists. Sanity precondition — canonical-establish
305	/// presumes the regime has been initialized at least to the marshal-zero
306	/// blank-template shape.
307	fn rbtdrk_probe_rbrr_present() -> Result<(), String> {
308	    let root = rbtdrk_probe_root()?;
309	    let rbrr = root.join(RBTDRK_RBRR_FILE);
310	    if !rbrr.exists() {
311	        return Err(format!("rbrr.env not found at {}", rbrr.display()));
312	    }
313	    Ok(())
314	}
315	
316	/// Case 2 probe: canonical depot moniker installed in rbrr.env. Established
317	/// by case 1; absence means depot-levy didn't run or rbrr.env was rewritten.
318	fn rbtdrk_probe_canonical_moniker() -> Result<(), String> {
319	    let root = rbtdrk_probe_root()?;
320	    let rbrr = root.join(RBTDRK_RBRR_FILE);
321	    let moniker =
322	        rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_DEPOT_MONIKER).unwrap_or_default();
323	    if !moniker.starts_with(RBTDRK_FAMILY_STEM) {
324	        return Err(format!(
325	            "{}={:?} does not begin with '{}' — canonical depot moniker not installed",
326	            RBTDRK_FIELD_RBRR_DEPOT_MONIKER, moniker, RBTDRK_FAMILY_STEM
327	        ));
328	    }
329	    Ok(())
330	}
331	
332	/// Cases 3 and 4 probe: governor RBRA file present at the canonical path.
333	/// Established by case 2's mantle + canonical-copy step.
334	fn rbtdrk_probe_governor_rbra() -> Result<(), String> {
335	    let root = rbtdrk_probe_root()?;
336	    let path = rbtdrk_canonical_rbra(&root, "governor")?;
337	    if !path.exists() {
338	        return Err(format!("governor RBRA absent at {}", path.display()));
339	    }
340	    Ok(())
341	}
342	
343	// ── Cases ────────────────────────────────────────────────────
344	
345	/// Case 1 — canonical depot levy. Installs canc-/canr- prefixes, picks a
346	/// fresh canest moniker, levies the depot, cross-checks project_id from
347	/// fact-file against the RBDC compose derivation.
348	fn rbtdrk_depot_levy(dir: &Path) -> rbtdre_Verdict {
349	    let probe = rbtdrb_Probe {
350	        name: "rbrr.env present",
351	        check: rbtdrk_probe_rbrr_present,
352	        remediation: "ensure regime is initialized — rerun pristine-lifecycle if needed",
353	    };
354	    if let Err(v) = rbtdrb_assert(&probe) {
355	        return v;
356	    }
357	    rbtdrc_with_ctx(|ctx| rbtdrk_depot_levy_impl(ctx, dir))
358	}
359	
360	fn rbtdrk_depot_levy_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
361	    let root = ctx.project_root().to_path_buf();
362	
363	    if let Err(e) = rbtdrk_install_canonical_prefixes(&root) {
364	        return rbtdre_Verdict::Fail(format!("install canonical prefixes: {}", e));
365	    }
366	
367	    let list_pre = match rbtdrk_invoke_logged(
368	        ctx,
369	        RBTDRM_COLOPHON_DEPOT_LIST,
370	        &[],
371	        &[],
372	        dir,
373	        "list-pre",
374	    ) {
375	        Ok(r) => r,
376	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (pre-levy): {}", e)),
377	    };
378	    if list_pre.exit_code != 0 {
379	        return rbtdre_Verdict::Fail(format!(
380	            "depot list (pre-levy) exit {}\n{}",
381	            list_pre.exit_code, list_pre.stderr
382	        ));
383	    }
384	
385	    let moniker = match rbtdrk_pick_next_moniker(&list_pre, RBTDRK_FAMILY_STEM) {
386	        Ok(m) => m,
387	        Err(e) => return rbtdre_Verdict::Fail(format!("pick next moniker: {}", e)),
388	    };
389	    if let Err(e) = rbtdrk_install_depot_moniker(&root, &moniker) {
390	        return rbtdre_Verdict::Fail(format!("install depot moniker: {}", e));
391	    }
392	
393	    let levy = match rbtdrk_invoke_logged(
394	        ctx,
395	        RBTDRM_COLOPHON_DEPOT_LEVY,
396	        &[],
397	        &[],
398	        dir,
399	        "levy",
400	    ) {
401	        Ok(r) => r,
402	        Err(e) => return rbtdre_Verdict::Fail(format!("depot levy: {}", e)),
403	    };
404	    if levy.exit_code != 0 {
405	        return rbtdre_Verdict::Fail(format!(
406	            "depot levy exit {}\n{}",
407	            levy.exit_code, levy.stderr
408	        ));
409	    }
410	
411	    let list_present = match rbtdrk_invoke_logged(
412	        ctx,
413	        RBTDRM_COLOPHON_DEPOT_LIST,
414	        &[],
415	        &[],
416	        dir,
417	        "list-present",
418	    ) {
419	        Ok(r) => r,
420	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after levy): {}", e)),
421	    };
422	    if list_present.exit_code != 0 {
423	        return rbtdre_Verdict::Fail(format!(
424	            "depot list (after levy) exit {}\n{}",
425	            list_present.exit_code, list_present.stderr
426	        ));
427	    }
428	
429	    let fact_path = list_present
430	        .burv_output
431	        .join(RBTDRI_BURV_OUTPUT_SUBDIR)
432	        .join(format!("{}.{}", moniker, RBTDRK_FACT_EXT_DEPOT_PROJECT));
433	    let fact_project_id = match std::fs::read_to_string(&fact_path) {
434	        Ok(s) => s.trim().to_string(),
435	        Err(e) => {
436	            return rbtdre_Verdict::Fail(format!(
437	                "read depot-project fact '{}': {}",
438	                fact_path.display(),
439	                e
440	            ))
441	        }
442	    };
443	    if fact_project_id.is_empty() {
444	        return rbtdre_Verdict::Fail(format!(
445	            "depot-project fact is empty: {}",
446	            fact_path.display()
447	        ));
448	    }
449	    let _ = std::fs::write(dir.join("project-id.txt"), &fact_project_id);
450	
451	    let composed = match rbtdrk_compose_project_id(&root, &moniker) {
452	        Ok(p) => p,
453	        Err(e) => return rbtdre_Verdict::Fail(format!("compose project_id: {}", e)),
454	    };
455	    if composed != fact_project_id {
456	        return rbtdre_Verdict::Fail(format!(
457	            "project_id mismatch: RBDC compose='{}' vs depot-list fact='{}' \
458	             (RBDC kindle derivation diverged from payor creation)",
459	            composed, fact_project_id
460	        ));
461	    }
462	    rbtdre_Verdict::Pass
463	}
464	
465	/// Case 2 — governor mantle. Mantles governor against the canonical depot,
466	/// reads the SA email fact, copies governor RBRA from BURV output to the
467	/// canonical path under RBRR_SECRETS_DIR.
468	fn rbtdrk_governor_mantle(dir: &Path) -> rbtdre_Verdict {
469	    let probe = rbtdrb_Probe {
470	        name: "canonical depot moniker installed",
471	        check: rbtdrk_probe_canonical_moniker,
472	        remediation: "rerun rbtdrk_depot_levy or the full canonical-establish fixture",
473	    };
474	    if let Err(v) = rbtdrb_assert(&probe) {
475	        return v;
476	    }
477	    rbtdrc_with_ctx(|ctx| rbtdrk_governor_mantle_impl(ctx, dir))
478	}
479	
480	fn rbtdrk_governor_mantle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
481	    let root = ctx.project_root().to_path_buf();
482	
483	    let assay = match rbtdrk_canonical_rbra(&root, "assay") {
484	        Ok(p) => p,
485	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical assay RBRA path: {}", e)),
486	    };
487	
488	    let mantle = match rbtdrk_invoke_logged(
489	        ctx,
490	        RBTDRM_COLOPHON_GOV_MANTLE,
491	        &[],
492	        &[],
493	        dir,
494	        "mantle",
495	    ) {
496	        Ok(r) => r,
497	        Err(e) => return rbtdre_Verdict::Fail(format!("governor mantle: {}", e)),
498	    };
499	    if mantle.exit_code != 0 {
500	        return rbtdre_Verdict::Fail(format!(
501	            "governor mantle exit {}\n{}",
502	            mantle.exit_code, mantle.stderr
503	        ));
504	    }
505	
506	    let email = match rbtdri_read_burv_fact(&mantle, RBTDRK_FACT_GOVERNOR_SA_EMAIL) {
507	        Ok(s) => s,
508	        Err(e) => return rbtdre_Verdict::Fail(format!("read governor SA email fact: {}", e)),
509	    };
510	    let _ = std::fs::write(dir.join("governor-sa-email.txt"), &email);
511	
512	    if !assay.exists() {
513	        return rbtdre_Verdict::Fail(format!(
514	            "assay RBRA absent after governor mantle: {}",
515	            assay.display()
516	        ));
517	    }
518	
519	    let canonical = match rbtdrk_canonical_rbra(&root, "governor") {
520	        Ok(p) => p,
521	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical governor RBRA path: {}", e)),
522	    };
523	    if let Some(parent) = canonical.parent() {
524	        if let Err(e) = std::fs::create_dir_all(parent) {
525	            return rbtdre_Verdict::Fail(format!(
526	                "create governor RBRA dir {}: {}",
527	                parent.display(),
528	                e
529	            ));
530	        }
531	    }
532	    if let Err(e) = std::fs::copy(&assay, &canonical) {
533	        return rbtdre_Verdict::Fail(format!(
534	            "copy assay RBRA → governor canonical {}: {}",
535	            canonical.display(),
536	            e
537	        ));
538	    }
539	    rbtdre_Verdict::Pass
540	}
541	
542	/// Case 3 — retriever invest + access-probe. The access-probe doubles as the
543	/// IAM-propagation gate: the invest tabtarget is responsible for waiting on
544	/// propagation before exiting (or the probe iterates internally). No separate
545	/// propagation-wait case.
546	fn rbtdrk_retriever_invest(dir: &Path) -> rbtdre_Verdict {
547	    let probe = rbtdrb_Probe {
548	        name: "governor RBRA present",
549	        check: rbtdrk_probe_governor_rbra,
550	        remediation: "rerun rbtdrk_governor_mantle or the full canonical-establish fixture",
551	    };
552	    if let Err(v) = rbtdrb_assert(&probe) {
553	        return v;
554	    }
555	    rbtdrc_with_ctx(|ctx| {
556	        rbtdrk_role_invest_impl(
557	            ctx,
558	            dir,
559	            RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
560	            RBTDRK_IDENTITY_RETRIEVER,
561	            "retriever",
562	        )
563	    })
564	}
565	
566	/// Case 4 — director invest + access-probe.
567	fn rbtdrk_director_invest(dir: &Path) -> rbtdre_Verdict {
568	    let probe = rbtdrb_Probe {
569	        name: "governor RBRA present",
570	        check: rbtdrk_probe_governor_rbra,
571	        remediation: "rerun rbtdrk_governor_mantle or the full canonical-establish fixture",
572	    };
573	    if let Err(v) = rbtdrb_assert(&probe) {
574	        return v;
575	    }
576	    rbtdrc_with_ctx(|ctx| {
577	        rbtdrk_role_invest_impl(
578	            ctx,
579	            dir,
580	            RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR,
581	            RBTDRK_IDENTITY_DIRECTOR,
582	            "director",
583	        )
584	    })
585	}
586	
587	/// Shared invest body for retriever and director: invest → assert assay
588	/// dropped by the invest tabtarget → copy to canonical role path → access-probe.
589	fn rbtdrk_role_invest_impl(
590	    ctx: &mut rbtdri_Context,
591	    dir: &Path,
592	    invest_colophon: &str,
593	    identity: &str,
594	    role: &str,
595	) -> rbtdre_Verdict {
596	    let root = ctx.project_root().to_path_buf();
597	
598	    let assay = match rbtdrk_canonical_rbra(&root, "assay") {
599	        Ok(p) => p,
600	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical assay RBRA path: {}", e)),
601	    };
602	
603	    let label_invest = format!("invest-{}", role);
604	    let invest = match rbtdrk_invoke_logged(
605	        ctx,
606	        invest_colophon,
607	        &[identity],
608	        &[],
609	        dir,
610	        &label_invest,
611	    ) {
612	        Ok(r) => r,
613	        Err(e) => return rbtdre_Verdict::Fail(format!("invest {}: {}", role, e)),
614	    };
615	    if invest.exit_code != 0 {
616	        return rbtdre_Verdict::Fail(format!(
617	            "invest {} exit {}\n{}",
618	            role, invest.exit_code, invest.stderr
619	        ));
620	    }
621	
622	    if !assay.exists() {
623	        return rbtdre_Verdict::Fail(format!(
624	            "assay RBRA absent after invest-{}: {}",
625	            role,
626	            assay.display()
627	        ));
628	    }
629	
630	    let canonical = match rbtdrk_canonical_rbra(&root, role) {
631	        Ok(p) => p,
632	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical {} RBRA path: {}", role, e)),
633	    };
634	    if let Some(parent) = canonical.parent() {
635	        if let Err(e) = std::fs::create_dir_all(parent) {
636	            return rbtdre_Verdict::Fail(format!(
637	                "create {} RBRA dir {}: {}",
638	                role,
639	                parent.display(),
640	                e
641	            ));
642	        }
643	    }
644	    if let Err(e) = std::fs::copy(&assay, &canonical) {
645	        return rbtdre_Verdict::Fail(format!(
646	            "copy assay RBRA → {} canonical {}: {}",
647	            role,
648	            canonical.display(),
649	            e
650	        ));
651	    }
652	
653	    let probe_result = match rbtdri_invoke_imprint(ctx, RBTDRM_COLOPHON_ACCESS_PROBE, role, &[]) {
654	        Ok(r) => r,
655	        Err(e) => {
656	            return rbtdre_Verdict::Fail(format!("access-probe {} invocation: {}", role, e))
657	        }
658	    };
659	    let _ = std::fs::write(
660	        dir.join(format!("probe-{}-stdout.txt", role)),
661	        &probe_result.stdout,
662	    );
663	    let _ = std::fs::write(
664	        dir.join(format!("probe-{}-stderr.txt", role)),
665	        &probe_result.stderr,
666	    );
667	    if probe_result.exit_code != 0 {
668	        return rbtdre_Verdict::Fail(format!(
669	            "access-probe {} exit {}\n{}",
670	            role, probe_result.exit_code, probe_result.stderr
671	        ));
672	    }
673	
674	    rbtdre_Verdict::Pass
675	}
676	
677	// ── Section registry ─────────────────────────────────────────
678	
679	pub static RBTDRK_SECTIONS_CANONICAL_ESTABLISH: &[rbtdre_Section] = &[rbtdre_Section {
680	    name: "canonical-establish-arc",
681	    cases: &[
682	        case!(rbtdrk_depot_levy),
683	        case!(rbtdrk_governor_mantle),
684	        case!(rbtdrk_retriever_invest),
685	        case!(rbtdrk_director_invest),
686	    ],
687	}];
688

